	.TITLE	HS6	.PROC	M680002	.REF	SMAKYLBREAD	=	H'10000LBWRITE	=	H'100	.LOC	0ONDMIDI:.BLKB	2		; no du driver MIDIONIMIDI:.BLKB	1		; 1 => driver MIDI pas install ici	.EVENOFLAGS:	.BLKB	1 BWAIT   = 0	.EVENOPDATA:	.BLKB	4OLDATA:	.BLKB	4OLWAIT:	.BLKB	4OBWRITE:.BLKB	LBWRITEOBREAD:	.BLKB	LBREADLGVAR:	.LOC	0START:	LOAD.L	A6,#0	LOAD.L	D4,#LGVAR	LOAD.W	D1,#MTYPCP	GESMEM	?GETMEM	JUMP,NE ERFAT	LOAD.L	A6,A4	LOAD.L	A4,A6	LOAD.L	D4,#LGVAR/210$:	CLR.W	(A4+)	DEC.L	D4	JUMP,NE 10$	CALL	OPEMIDI	JUMP,NE ERFATLOOP:	LIB	?AFTIM	.B	CR	.ASCIZ	"(L)it, (E)crit, (END) ? "	.EVEN	LIB	?GETCAR	LIB	?MINMAJ	COMP.W	D3,#END	JUMP,EQ RETOUR	COMP.W	D3,#'L	JUMP,EQ LIT	COMP.W	D3,#'E	JUMP,EQ ECRIT	JUMP	LOOPLIT:	LIB	?AFTIM	.B	CR	.ASCIZ	"Message hexa : "	.EVEN	LIB	?GETHEX	COMP.W	D3,#CR	JUMP,NE LOOP	LOAD.B	D3,D4	CALL	WAITMSG		; attend rponse ...	LOAD.L	(A6)+OPDATA,A4	LOAD.L	(A6)+OLDATA,D4	LIB	?AFTIM	.B	CR	.ASCIZ	"Longueur reue = H'"	.EVEN	LIB	?AFX8	LIB	?AFCR	LOAD.W	D2,#2050$:	LOAD.B	D4,(A4+)	LIB	?AFX2	LIB	?AFSPACE	DEC.W	D2	JUMP,NE 50$	LIB	?AFCR	JUMP	LOOPECRIT:	LIB	?AFTIM	.B	CR	.ASCIZ	"Message hexa : "	.EVEN	LIB	?GETHEX	COMP.W	D3,#CR	JUMP,NE LOOP	LOAD.B	D3,D4	LOAD.L	A4,(A6)+OPDATA	LOAD.L	D4,(A6)+OLDATA	CALL	SENDMSG		; crit le message ...	JUMP	LOOPRETOUR:	CALL	STOPMIDI	CALL	CLOMIDIFINI:	COMP.L	A6,#0	JUMP,EQ 90$	LOAD.L	A4,A6	LOAD.W	D1,#MTYPCP	GESMEM	?GIVMEM90$:	EXITERFAT:	LIB	?AFTIM	.ASCIZ	"--ERREUR--"	.EVEN	JUMP	FINI;--------\\; WAITMSG >;========/; Demande quelque chose, et attend la rponse.; in	D3.B	message  envoyer; out	A4.L	^data reu;	D4.L	lg data reu;	D7.W	erreur; mod	D4.L, D7.W, A4.LWAITMSG:	PUSHM.L	D2,D3,D5,A3,A5	LOAD.B	D2,D3		; D2 <-- message	TSET.B	(A6)+OFLAGS:#BWAIT	NTREL	?GETPRIO	; D4 <-- priorit	DEC.W	D4	LOAD.L	D5,#600		; D5 <-- lg stack	LOAD.L	A5,#R16"PWAIT	; A5 <-- ^start	LOAD.L	A3,#R16"NWAIT	; A3 <-- ^nom	NTREL	?CRETASK	; dmarre la rception	JUMP,NE 90$30$:	LIB	?IFCAR		; vide le fifo du clavier !	JUMP,EQ 30$	LOAD.L	A4,#(A6)+OBWRITE	LOAD.B	(A4)+0,#0	LOAD.B	(A4)+1,#6	LOAD.B	(A4)+2,#H'F0	LOAD.B	(A4)+3,#H'43	LOAD.B	(A4)+4,#H'70	LOAD.B	(A4)+5,#H'70	LOAD.B	(A4)+6,D2	LOAD.B	(A4)+7,#H'F7	CALL	WRMIDI	LOAD.W	D2,#10*10	; D2 <-- attend 10 secondes maximum40$:	CLR.W	D7		; D7 <-- ok	TEST.B	(A6)+OFLAGS:#BWAIT	JUMP,BC 45$	LIB	?IFCAR		; touche presse ?	JUMP,EQ 44$		; oui => 44$	LOAD.W	D4,#50/10	NTREL	?DELMS		; attend un peu ...	DEC.W	D2	JUMP,NE 40$44$:	LOAD.W	D7,#ERUNCO	; D7 <-- unit pas connecte45$:	PUSH.W	D7	CALL	STOPMIDI	; stoppe tout	POP.W	D7	LOAD.L	A4,#(A6)+OBREAD	; A4 <-- ^data reu	LOAD.L	D4,(A6)+OLWAIT	; D4 <-- lg data reu50$:	COMP.L	D4,#4	JUMP,LO 90$	TEST.W	(A4)		; indication de temps ?	JUMP,NE 90$		; non => 90$				; oui =>	ADD.L	A4,#4		; A4 <-- saute le temps	SUB.L	D4,#4	JUMP	50$90$:	POPM.L	D2,D3,D5,A3,A5	TEST.W	D7		; retour EQ/NE	RET;;;;;;;;;;;;;;;    WAIT    ;;;;;;;;;;;;;;;NWAIT:	.ASCIZ	"MIDI_WAIT"	.EVENPWAIT:	LOAD.L	A4,#(A6)+OBREAD	LOAD.L	D5,#LBREAD-10	LOAD.W	D2,(A6)+ONDMIDI	BIOS	?DREAD	LOAD.L	(A6)+OLWAIT,D5	TCLR.B	(A6)+OFLAGS:#BWAIT	NTREL	?ABORT;--------\\; SENDMSG >;========/; Envoie un message.; in	D3.B	message;	A4.L	^data;	D4.L	lg data; out	D7.W	erreur; mod	D7.WSENDMSG:	PUSHM.L	D4,A4	PUSH.L	A4	LOAD.L	A4,#(A6)+OBWRITE	LOAD.B	(A4)+0,#0	LOAD.B	(A4)+1,#6	LOAD.B	(A4)+2,#H'F0	LOAD.B	(A4)+3,#H'43	LOAD.B	(A4)+4,#H'70	LOAD.B	(A4)+5,#H'70	LOAD.B	(A4)+6,D3	LOAD.B	(A4)+7,#H'F7	CALL	WRMIDI	POP.L	A4;;?	LOAD.B	(A4)+5,#H'70	LOAD.B	(A4)+6,#H'00	CALL	WRMIDI	POPM.L	D4,A4	TEST.W	D7		; retour EQ/NE	RET;--------\\; WRMIDI  >;========/; Ecrit plusieurs bytes sur MIDI.; in	A4.L	^<<lg>>data; out	D7.W	erreur; mod	D7.WWRMIDI:	PUSHM.L	D2,D5	CLR.L	D5	LOAD.W	D5,(A4)	ADD.W	D5,#2	LOAD.W	D2,(A6)+ONDMIDI	BIOS	?DWRITE		; crit tout a	POPM.L	D2,D5	TEST.W	D7		; retour EQ/NE	RET;--------\\; COMMAND >;========/; Envoie une commande  MIDI.; in	A4.L	^commande; out	D7.W	erreur; mod	D7.WCOMMAND:	PUSHM.L	D1,D2	LOAD.W	D1,#TYPIO	; D1 <-- type	LOAD.W	D2,(A6)+ONDMIDI	BIOS	?DCOMMAND	POPM.L	D1,D2	TEST.W	D7		; retour EQ/NE	RET;---------\\; STOPMIDI >;=========/; Stoppe compltement MIDI.; in	-; out	-; mod	D7.WSTOPMIDI:	PUSH.L	D2	LOAD.W	D2,(A6)+ONDMIDI	BIOS	?DAVOTR		; avort lecture/criture;;?	NTREL	?WFABDESC	; attend la fin des processus fils	POP.L	D2	RET;--------\\; OPEMIDI >;========/; Ouvre le driver MIDI.; in	-; out	D7.W	erreur; mod	D7.WOPEMIDI:	PUSHM.L	D2,D3,A2..A4; Dinstalle l'usart en utilisant les noms #PR, #PP, #MI et #MO.	LOAD.L	A3,#R16"LUSART0	CLR.W	D3		; D3 <-- pour tous	FOS	?DEINSTALL	LOAD.L	A3,#R16"LUSART1;	CLR.W	D3		; D3 <-- pour tous	FOS	?DEINSTALL	LOAD.L	A3,#R16"LUSART2;	CLR.W	D3		; D3 <-- pour tous	FOS	?DEINSTALL	LOAD.L	A3,#R16"LUSART3;	CLR.W	D3		; D3 <-- pour tous	FOS	?DEINSTALL; Installe le driver MIDI  la place de l'usart.	CLR.B	(A6)+ONIMIDI	; driver MIDI install ici	LOAD.L	A3,#R16"LMIDI	; A3 <-- ^nom logique	LOAD.L	A4,#R16"PMIDI	; A4 <-- ^nom physique	LOAD.L	A2,#0		; A2 <-- ^paramtres;	CLR.W	D3		; D3 <-- pour tous	FOS	?INSTALL	; install le driver	JUMP,EQ 50$	COMP.W	D7,#ERUUSE	; dj install ?	JUMP,NE	90$		; non => 90$				; oui =>	SET.B	(A6)+ONIMIDI	; driver MIDI pas install ici50$:	LOAD.L	A3,#R16"DMIDI	FOS	?UNAMDRIV	; D2 <-- numro de driver	JUMP,NE	90$	LOAD.W	(A6)+ONDMIDI,D2	90$:	POPM.L	D2,D3,A2..A4	TEST.W	D7		; retour EQ/NE	RET;--------\\; CLOMIDI >;========/; Ferme le driver MIDI.; in	-; out	-; mod	D7.WCLOMIDI:	PUSHM.L	D3,A3	TEST.B	(A6)+ONIMIDI	; driver MIDI install ici ?	JUMP,T	90$		; non => 90$	LOAD.L	A3,#R16"LMIDI	; A3 <-- ^nom logique	CLR.W	D3		; D3 <-- pour tous	FOS	?DEINSTALL	; dinstall le driver90$:	POPM.L	D3,A3	RET; Textes; ------LUSART0:.ASCIZ	"#PR"LUSART1:.ASCIZ	"#PP"LUSART2:.ASCIZ	"#MI"LUSART3:.ASCIZ	"#MO"LMIDI:	.ASCIZ	"#MIDI:"PMIDI:	.ASCIZ	"$MIDI_0"DMIDI:	.ASCIZ	"MIDI_0"	.EVEN	.END	START